import React, { useState } from "react";
import {
  Box,
  Drawer,
  List,
  ListItem,
  ListItemText,
  AppBar,
  Toolbar,
  Typography,
  Container as MuiContainer,
  IconButton,
} from "@mui/material";
import MenuIcon from "@mui/icons-material/Menu";
import ChartistGraph from "react-chartist"; // Importing ChartistGraph for the charts
import { Card, Row, Col } from "react-bootstrap"; // Importing Bootstrap components for layout and styling
import Login from "./login.js";
import ResourceSearch from "./resource-search.js";
import ModerationForm from "./moderation.js";
import NewPassword from "./new-password.js";
import RateResource from "./rate-resource.js";
import Register from "./register.js";
import PasswordReset from "./reset-password.js";
import ResourceReport from "./resource-report.js";
import UpdateUserRole from "./update-user-role.js";
import UploadTaggingResource from "./file-upload-tagging.js";
import SubjectView from "./subject-view.js";
import FAQ from "./faq.js";
import AboutUs from "./about-us.js";
import OER from "./oer.js";
import Contributors from "./contributors.js";
import Self from "./sdl.js";
import Analytics from "./analytics.js";

const Home = () => {
  const [searchQuery, setSearchQuery] = useState("");
  const [activeSection, setActiveSection] = useState("overview");
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const handleSearch = (e) => {
    e.preventDefault();
    console.log("Search query:", searchQuery);
  };

  const renderDashboardContent = () => {
    return (
      <>
        <MuiContainer fluid>
          <Row>
            <Col lg="3" sm="6">
              <Card className="card-stats">
                <Card.Body>
                  <Row>
                    <Col xs="5">
                      <div className="icon-big text-center icon-warning">
                        <i className="nc-icon nc-light-3 text-success"></i>
                      </div>
                    </Col>
                    <Col xs="7">
                      <div className="numbers">
                        <p className="card-category">Revenue</p>
                        <Card.Title as="h4">$ 1,345</Card.Title>
                      </div>
                    </Col>
                  </Row>
                </Card.Body>
              </Card>
            </Col>
          </Row>
          {/* Additional Dashboard components like charts */}
          <Row>
            <Col md="8">
              <Card>
                <Card.Header>
                  <Card.Title as="h4">Users Behavior</Card.Title>
                  <p className="card-category">24 Hours performance</p>
                </Card.Header>
                <Card.Body>
                  <div className="ct-chart" id="chartHours">
                    <ChartistGraph
                      data={{
                        labels: [
                          "9:00AM",
                          "12:00AM",
                          "3:00PM",
                          "6:00PM",
                          "9:00PM",
                          "12:00PM",
                          "3:00AM",
                          "6:00AM",
                        ],
                        series: [
                          [287, 385, 490, 492, 554, 586, 698, 695],
                          [67, 152, 143, 240, 287, 335, 435, 437],
                          [23, 113, 67, 108, 190, 239, 307, 308],
                        ],
                      }}
                      type="Line"
                      options={{
                        low: 0,
                        high: 800,
                        showArea: false,
                        height: "245px",
                        axisX: {
                          showGrid: false,
                        },
                        lineSmooth: true,
                        showLine: true,
                        showPoint: true,
                        fullWidth: true,
                        chartPadding: {
                          right: 50,
                        },
                      }}
                      responsiveOptions={[
                        [
                          "screen and (max-width: 640px)",
                          {
                            axisX: {
                              labelInterpolationFnc: function (value) {
                                return value[0];
                              },
                            },
                          },
                        ],
                      ]}
                    />
                  </div>
                </Card.Body>
              </Card>
            </Col>
            <Col md="4">
              <Card>
                <Card.Header>
                  <Card.Title as="h4">Email Statistics</Card.Title>
                  <p className="card-category">Last Campaign Performance</p>
                </Card.Header>
                <Card.Body>
                  <div
                    className="ct-chart ct-perfect-fourth"
                    id="chartPreferences"
                  >
                    <ChartistGraph
                      data={{
                        labels: ["40%", "20%", "40%"],
                        series: [40, 20, 40],
                      }}
                      type="Pie"
                    />
                  </div>
                </Card.Body>
              </Card>
            </Col>
          </Row>
        </MuiContainer>
      </>
    );
  };

  const renderSectionContent = () => {
    switch (activeSection) {
      case "subject-view":
        return <SubjectView />;
      case "resource-search":
        return <ResourceSearch />;
      case "file-upload":
        return <UploadTaggingResource />;
      case "oer":
        return <OER />;
      case "contributors":
        return <Contributors />;
      case "self-directed":
        return <Self />;
      case "register":
        return <Register />;
      case "reset-password":
        return <PasswordReset />;
      case "new-password":
        return <NewPassword />;
      case "about-us":
        return <AboutUs />;
      case "faq":
        return <FAQ />;
      case "login":
        return <Login />;
      case "analytics":
        return <Analytics />;
      case "moderate":
        return <ModerationForm />;
      case "rate-resource":
        return <RateResource />;
      case "resource-report":
        return <ResourceReport />;
      case "update-user-role":
        return <UpdateUserRole />;
      case "dashboard": // Case for rendering the dashboard
        return renderDashboardContent();
      default:
        return <Typography variant="h5">Welcome to Share2Teach</Typography>;
    }
  };

  const handleItemClick = (section) => {
    setActiveSection(section);
    setSidebarOpen(false);
  };

  return (
    <Box sx={{ display: "flex", height: "100vh", bgcolor: "#E3F2FD" }}>
      {/* Sidebar Drawer */}
      <Drawer
        variant="temporary"
        anchor="left"
        open={sidebarOpen}
        onClose={() => setSidebarOpen(false)}
        sx={{
          "& .MuiDrawer-paper": {
            width: 240,
            bgcolor: "#2c7b2f",
            color: "white",
            transition: "all 0.3s ease-in-out",
          },
        }}
      >
        <List>
          {[
            { text: "Home", section: "/" },
            { text: "Subject View", section: "subject-view" },
            { text: "Search Resources", section: "resource-search" },
            { text: "Contribute", section: "file-upload" },
            { text: "Dashboard", section: "dashboard" }, // Add "Dashboard" to the menu
            { text: "Other Useful OERs", section: "oer" },
            { text: "Rate Resources", section: "rate-resource" },
            { text: "Moderate Resources", section: "moderate" },
            { text: "Contributors", section: "contributors" },
            { text: "Self-Directed Learning", section: "self-directed" },
            { text: "Login", section: "login" },
            { text: "Account Creation", section: "register" },
            { text: "Password Reset", section: "reset-password" },
            { text: "New Reset", section: "new-password" },
            { text: "Analytics", section: "analytics" },
            { text: "About Us", section: "about-us" },
            { text: "FAQ", section: "faq" },
            { text: "Resource Report", section: "resource-report" },
            { text: "Update User Role", section: "update-user-role" },
          ].map(({ text, section }) => (
            <ListItem
              button
              key={text}
              onClick={() => handleItemClick(section)}
              sx={{
                "&:hover": {
                  bgcolor: "#388e3c",
                  transition: "background-color 0.3s ease",
                },
              }}
            >
              <ListItemText primary={text} />
            </ListItem>
          ))}
        </List>
      </Drawer>
      {/* Main Content */}
      <Box
        sx={{
          flexGrow: 1,
          transition: "margin-left 0.3s, transform 0.3s ease",
          marginLeft: sidebarOpen ? "240px" : "0",
        }}
      >
        <AppBar position="static" sx={{ bgcolor: "#4caf50" }}>
          <Toolbar>
            <IconButton
              edge="start"
              color="inherit"
              aria-label="menu"
              onClick={() => setSidebarOpen(true)}
            >
              <MenuIcon />
            </IconButton>
            <Typography variant="h6" component="div" sx={{ flexGrow: 1 }}>
              Share2Teach
            </Typography>
          </Toolbar>
        </AppBar>
        <MuiContainer sx={{ padding: 2, overflowY: "auto" }}>
          <div className="text-center mb-4">
            <img
              src="https://services.nwu.ac.za/sites/services.nwu.ac.za/files/files/designs-branding/NWU-Stacked-Logo-Black-Digital.png"
              alt="Share2Teach"
              className="img-fluid"
              width={50}
            />
          </div>
          <Box
            sx={{
              padding: 2,
              bgcolor: "#ffffff",
              borderRadius: 2,
              animation: "fadeIn 0.5s ease",
              "@keyframes fadeIn": {
                "0%": { opacity: 0 },
                "100%": { opacity: 1 },
              },
            }}
          >
            {renderSectionContent()}
          </Box>
        </MuiContainer>
      </Box>
    </Box>
  );
};

export default Home;
